diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 76234ccfdcff..a625ee6d125c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2029,6 +2029,35 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     // C-(C2-X) --> X+(C-C2)
     if (match(Op1, m_Sub(m_ImmConstant(C2), m_Value(X))))
       return BinaryOperator::CreateAdd(X, ConstantExpr::getSub(C, C2));
+
+    // C - ((C1 - X) & M1) --> X & M2
+    // Where C1 - C = K is of the form 2^n - 1 (all 1s in binary),
+    // M1 = ~K, and M2 has bits [n : 2n] set.
+    // Example: 64 - ((71 - X) & -8) --> X & 120
+    // This relies on the nuw flag of (C1 - X) to ensure correctness.
+    if (auto *CI = dyn_cast<ConstantInt>(C)) {
+      APInt CVal = CI->getValue();
+      Value *AndOpnd, *X;
+      const APInt *AndC, *SubC;
+      BinaryOperator *Sub;
+      if (match(Op1, m_And(m_Value(AndOpnd), m_APInt(AndC))) &&
+          match(AndOpnd, m_OneUse(m_Sub(m_APInt(SubC), m_Value(X)))) &&
+          (Sub = dyn_cast<BinaryOperator>(AndOpnd))->hasNoUnsignedWrap()) {
+        APInt K = *SubC - CVal;
+        // Check if K is of the form 2^n - 1 (all 1s)
+        if (K.isMask()) {
+          unsigned N = K.getActiveBits();
+          // M1 should be ~K (i.e., -2^N)
+          APInt M1 = ~K;
+          if (*AndC == M1) {
+            // M2 has bits [N : 2N] set
+            APInt M2 = APInt::getBitsSet(I.getType()->getScalarSizeInBits(), N, 2 * N + 1);
+            return BinaryOperator::CreateAnd(
+                X, ConstantInt::get(I.getType(), M2));
+          }
+        }
+      }
+    }
   }

   const APInt *Op0C;

